import { FieldValues, useForm } from 'react-hook-form';

import { InputState } from '#components/FormInput/TextInput.types';

/*
 * This builds on top of the react-hook-form library
 * to provide a consistent handling of form state
 *
 * Designed to be used with TextInput & PasswordInput
 * and could be extended to support other input types
 *
 */
const useIndyForm = <T extends FieldValues>() => {
  const methods = useForm<T>({
    mode: 'onTouched',
  });

  const { formState } = methods;

  const getTextInputError = (id: keyof T) => formState.errors[id]?.message;
  const getTextInputState = (id: keyof T) => {
    const isErrored = !!formState.errors[id];
    const hasErrored = formState.dirtyFields[id as string] && !isErrored;

    if (isErrored) {
      return InputState.ERROR;
    }

    if (hasErrored) {
      return InputState.SUCCESS;
    }

    return InputState.DEFAULT;
  };

  const registerWithState = (id: keyof T) => ({
    id: id as keyof T,
    state: getTextInputState(id),
    message: getTextInputError(id),
  });

  return { methods, registerWithState };
};

export default useIndyForm;
