import React from 'react';
import {
  SubmitHandler,
  SubmitErrorHandler,
  FormProvider,
} from 'react-hook-form';

import Button from '#components/Button';
import Form from '#components/Form';
import TextInput, { PasswordInput } from '#components/FormInput';

import useIndyForm from '#hooks/useIndyForm';
import { Wrapper } from './TestableForm.styles';

type ExampleFormData = {
  fullName: string;
  email: string;
  password: string;
};

type SubmissionHandler = SubmitHandler<ExampleFormData>;
type ErrorHandler = SubmitErrorHandler<ExampleFormData>;

const EMAIL_REGEXP = new RegExp(/^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i);
/*
  This form exists to demonstrate how to use the useIndyForm hook
  alongside the Form, TextInput and PasswordInput components

  It us also used for testing functionality in a form context
  with full validation and error handling, and providing a
  component in storybook for visual testing
*/
const TestableForm: React.FC = () => {
  const { methods, registerWithState } = useIndyForm<ExampleFormData>();
  const { handleSubmit, formState } = methods;

  const onSubmit: SubmissionHandler = (data) => {
    alert(`submitted ${JSON.stringify(data)}`);
  };

  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const onError: ErrorHandler = (data) => {
    alert('error');
  };

  return (
    <Wrapper>
      <FormProvider {...methods}>
        <Form>
          <TextInput label="Name" minLength={3} {...registerWithState('fullName')} />
          <TextInput
            type="email"
            label="Email address"
            helpText="Add an email address"
            required={true}
            pattern={{
              value: EMAIL_REGEXP,
              message: 'Please enter a valid email address',
            }}
            {...registerWithState('email')}
          />
          <PasswordInput
            label="Password"
            required={true}
            helpText="Make it a good one"
            {...registerWithState('password')}
          />
          <Button
            type="submit"
            disabled={!formState.isValid}
            onClick={handleSubmit(onSubmit, onError)}
          >
            Sign up
          </Button>
        </Form>
      </FormProvider>
    </Wrapper>
  );
};

export default TestableForm;
