import React, { FormEvent, PropsWithChildren } from 'react';

const Form: React.FC<PropsWithChildren> = ({ children }) => {
  // Rely on our own validation and styling
  const noValidate = true;

  /*
    We prevent form submission here to prevent key presses (e.g. enter, space) from
    submitting the form unintentionally or interfering with custom input behaviour
    (i.e. toggle password visibility)

    Forms using this component should make use of a button with a onClick handler to
    handle submission instead
  */
  const preventSubmission = (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
  };

  return (
    <form noValidate={noValidate} onSubmit={preventSubmission}>
      {children}
    </form>
  );
};

export default Form;
